INSERT INTO products (external_id, cat_number, name, old_price, price, image, link, short_desc, `desc`, full_desc, in_stock, status) VALUES
('010', 'No.0', 'OLAPLEX Hair Treatment', 3980, 2990, 'data/images/ID010_min.png', '/hair_perfector_0', '1 x 155 ml <strong>Olaplex No.0 Hair Treatment | Интенсивный уход-праймер «Активное восстановление» </strong>', 'Olaplex Hair Treatment No. 0 – уникальное средство для защиты волос во время окрашивания. Проникая внутрь волосков, восстанавливает поврежденную структуру, придает эластичность и обеспечивает длительную защиту от химических, термических и механических повреждений. Даже после одного использования волосы становятся гладкими, блестящими и здоровыми.', 'Olaplex Hair Treatment No. 0 – уникальное средство для защиты волос во время окрашивания. Проникая внутрь волосков, восстанавливает поврежденную структуру, придает эластичность и обеспечивает длительную защиту от химических, термических и механических повреждений. Даже после одного использования волосы становятся гладкими, блестящими и здоровыми.<br><b>Применение:</b> Пропитайте сухие волосы по всей длине Olaplex No.0. Выдержите 10 минут. Для наилучшего результата не смывая нанесите Olaplex No.3 и выдержите еще 10 минут. Ополосните водой, используйте шампунь и кондиционер.', 1, 'active'),
('002', 'No.2', 'OLAPLEX Hair Perfector', 16500, 14900, 'data/images/ID002_min.png', '/bond_perfector', '1 x 525 ml <strong>Olaplex No.2 Bond Perfector | Коктейль-фиксатор волос</strong>', 'Средство для волос Bond Perfector – не кондиционер, не активатор и не нейтрализатор. Фиксирующий коктейль включает в себя тот самый компонент, что и Multiplier. Olaplex №2 создан для поиска и воссоединения разорванных соединений. Легко наносится на влажные волосы после салонных процедур.', 'Средство для волос Bond Perfector – не кондиционер, не активатор и не нейтрализатор. Фиксирующий коктейль включает в себя тот самый компонент, что и Multiplier. Olaplex №2 создан для поиска и воссоединения разорванных соединений. Легко наносится на влажные волосы после салонных процедур.<br><b>Применение:</b> смойте краситель или блондирующий состав. Не используйте шампунь. Если необходимо, выполните тонирование. Подсушите волосы с помощью полотенца. Нанести необходимое количество Olaplex Bond Perfector №2 Коктейль-фиксатор минимум на 10 мин. Смойте водой. Затем используйте шампунь и кондиционер.', 1, 'active'),
('028', 'No.3', 'OLAPLEX Hair Perfector', 1990, 1550, 'data/images/ID028_min.png', '/hair_perfector_50', '1 x 50ml <strong>Olaplex No.3 Hair Perfector | Эликсир «Совершенство Волос»</strong>', 'Интенсивный уход для восстановления поврежденных волос. Запатентованная технология Olaplex укрепляет структуру волос изнутри, делает их более гладкими, эластичными и здоровыми. Подходит для всех типов волос, особенно ослабленных окрашиванием, термоукладкой и химическими процедурами.', 'Интенсивный уход для восстановления поврежденных волос. Запатентованная технология Olaplex укрепляет структуру волос изнутри, делает их более гладкими, эластичными и здоровыми. Подходит для всех типов волос, особенно ослабленных окрашиванием, термоукладкой и химическими процедурами.<br><b>Применение:</b> Нанесите на влажные волосы перед мытьем шампунем, равномерно распределите и оставьте на 10-15 минут, затем тщательно смойте и используйте привычные средства ухода. Рекомендуется применять 1-2 раза в неделю.', 1, 'active'),
('001', 'No.3', 'OLAPLEX Hair Perfector', 3450, 2650, 'data/images/ID001_min.png', '/hair_perfector', '1 x 100ml <strong>Olaplex No.3 Hair Perfector | Эликсир «Совершенство Волос»</strong>', 'Предусмотрен на 8 использований. Используется для домашнего ухода в зависимости от потребности. Действующий компонент Olaplex в достаточной концентрации возмещает повседневные травмы волос, результативно восстанавливает и сохраняет их здоровье после применения профессионального комплекса ухода Олаплекс. Безупречно подготавливает волосы к любым услугам, предоставляемым в салонах красоты, таких как осветление, обесцвечивание или окрашивание.', 'Предусмотрен на 8 использований. Используется для домашнего ухода в зависимости от потребности. Действующий компонент Olaplex в достаточной концентрации возмещает повседневные травмы волос, результативно восстанавливает и сохраняет их здоровье после применения профессионального комплекса ухода Олаплекс. Безупречно подготавливает волосы к любым услугам, предоставляемым в салонах красоты, таких как осветление, обесцвечивание или окрашивание.<br><b>Применение:</b> Нанести достаточное количество Olaplex No.3 на влажные, подсушенные полотенцем волосы. Время выдержки — минимум 10 минут. Для поврежденных волос — не смывая, нанести средство повторно минимум на 10 минут. При необходимости можно использовать чаще без каких-либо ограничений.', 1, 'active'),
('011', 'No.3', 'OLAPLEX Hair Perfector', 8350, 6190, 'data/images/ID011_min.png', '/hair_perfector_03', '1 x 250ml <strong>Olaplex No.3 Hair Perfector | Эликсир «Совершенство Волос»</strong>', 'Olaplex Hair Perfector No. 3  возвращает здоровье, красоту и силу сухим, ломким волосам. Средство проникает в структуру волос на молекулярном уровне, насыщая его полезными компонентами, и обеспечивает длительную надежную защиту. Рекомендуется использовать на окрашенных волосах, а также при регулярном термическом и механическом воздействии на локоны. Регулярное применение позволит волосам всегда быть эластичными, сильными и блестящими. Нанести небольшое количество средства, оставить на прядях на несколько минут и затем смыть шампунем.', 'Olaplex Hair Perfector No. 3  возвращает здоровье, красоту и силу сухим, ломким волосам. Средство проникает в структуру волос на молекулярном уровне, насыщая его полезными компонентами, и обеспечивает длительную надежную защиту. Рекомендуется использовать на окрашенных волосах, а также при регулярном термическом и механическом воздействии на локоны. Регулярное применение позволит волосам всегда быть эластичными, сильными и блестящими. Нанести небольшое количество средства, оставить на прядях на несколько минут и затем смыть шампунем.<br><b>Применение:</b> Нанести достаточное количество Olaplex No.3 на влажные, подсушенные полотенцем волосы. Время выдержки — минимум 10 минут. Для поврежденных волос — не смывая, нанести средство повторно минимум на 10 минут. При необходимости можно использовать чаще без каких-либо ограничений.', 1, 'active'),
('032', 'No.4', 'OLAPLEX Bond Maintenance Shampoo', 2850, 1650, 'data/images/ID032_min.png', '/bond_maintenance_shampoo_100', '1 x 100 ml <strong>Olaplex N°4 Bond Maintenance Shampoo | Восстанавливающий шампунь для всех типов волос</strong>', 'Шампунь N°4 Bond Maintenance Shampoo эффективно очищает кожу головы, тщательно моет волосы и возвращает им естественную красоту. Восстанавливает и питает волосы укрепляет корни волос интенсивно увлажняет придает блеск и объем.', '', 1, 'active'),
('006', 'No.4', 'OLAPLEX Bond Maintenance Shampoo', 3550, 2890, 'data/images/ID006_min.png', '/bond_maintenance_shampoo', '1 x 250 ml <strong>Olaplex N°4 Bond Maintenance Shampoo | Восстанавливающий шампунь для всех типов волос</strong>', 'Шампунь N°4 Bond Maintenance Shampoo эффективно очищает кожу головы, тщательно моет волосы и возвращает им естественную красоту. Восстанавливает и питает волосы укрепляет корни волос интенсивно увлажняет придает блеск и объем.', '', 1, 'active'),
('021', 'No.4', 'OLAPLEX Bond Maintenance Shampoo', 13200, 9790, 'data/images/ID021_min.png', '/bond_maintenance_shampoo_1000', '1 x 1000 ml <strong>Olaplex N°4 Bond Maintenance Shampoo | Восстанавливающий шампунь для всех типов волос</strong>', 'Шампунь N°4 Bond Maintenance Shampoo эффективно очищает кожу головы, тщательно моет волосы и возвращает им естественную красоту. Восстанавливает и питает волосы укрепляет корни волос интенсивно увлажняет придает блеск и объем.', '', 1, 'active'),
('024', 'No.4C', 'OLAPLEX Bond Maintenance Clarifying Shampoo', 3780, 2990, 'data/images/ID024_min.png', '/bond_maintenance_clarifying_shampoo', '1 x 250 ml <strong>Olaplex No.4C Bond Maintenance Clarifying Shampoo | Очищающий шампунь </strong>', 'Шампунь Olaplex No.4C Bond Maintenance Clarifying Shampoo предназначен для еженедельного использования вместо обычного шампуня и обеспечивает глубокое очищение волос от загрязнений, скоплений кожного жира и остатков стайлинговых средств.', 'Шампунь Olaplex No.4C Bond Maintenance Clarifying Shampoo предназначен для еженедельного использования вместо обычного шампуня и обеспечивает глубокое очищение волос от загрязнений, скоплений кожного жира и остатков стайлинговых средств.<br>Формула шампуня использует передовую систему очищения для удаления широкого спектра загрязнений, включая минералы жесткой воды, хлор, тяжелые металлы и остатки продуктов, при этом не лишая и не пересушивая волосы. Благодаря запатентованной технологии Bond Building Technology™, шампунь придает волосам приятную на ощупь мягкость и оптимально подготавливает их к следующим этапам процедуры Olaplex.Подходит для всех типов волос.<br><b>Способ применения:</b>Наносить на влажные волосы, массировать, через 1-2 минуты тщательно смыть. Для получения максимального результата использовать в комплексе с маской от Olaplex.', 1, 'active'),
('025', 'No.4D', 'OLAPLEX Clean Volume Detox Dry Shampoo', 3770, 2990, 'data/images/ID025_min.png', '/4D_clean_volume_detox_dry_shampo', '1 x 250 ml <strong>Olaplex No. 4D Clean Volume Detox Dry Shampoo | Сухой шампунь </strong>', 'Сухой шампунь Olaplex выводит токсины из кожи головы, отталкивает запахи, придает объем и очищает волосы. Clean Volume Detox — это формула сухой чистки, содержащая полезные для ухода за кожей ингредиенты, которые выводят токсины и поддерживают здоровье кожи головы между мытьем. Кроме того, новый сухой шампунь от Olaplex, придающий объем волосам, наверняка станет бестселлером. Здоровая кожа головы – залог чистых и здоровых волос.', 'Сухой шампунь Olaplex выводит токсины из кожи головы, отталкивает запахи, придает объем и очищает волосы. Clean Volume Detox — это формула сухой чистки, содержащая полезные для ухода за кожей ингредиенты, которые выводят токсины и поддерживают здоровье кожи головы между мытьем. Кроме того, новый сухой шампунь от Olaplex, придающий объем волосам, наверняка станет бестселлером. Здоровая кожа головы – залог чистых и здоровых волос.<br><b>Способ применения:</b>Встряхните перед использованием, разделите волосы на пряди и распылите с расстояния 15-20 см. Подождите 30 секунд, а затем массируйте волосы и кожу головы.', 1, 'active'),
('016', 'No.4P', 'OLAPLEX Blonde Enhancer Toning Shampoo', 3940, 3290, 'data/images/ID016_min.png', '/olaplex_blonde_enhancer_toning_shampoo', '1 x 250ml <strong>Olaplex Blonde Enhancer Toning Shampoo | Тонирующий шампунь для светлых волос</strong>', 'Тонирующий шампунь "Система защиты для светлых волос" с запатентованной технологией Olaplex укрепляет, смягчает и нейтрализует нежелательные оттенки желтого, делая волосы мягкими, яркими и послушными. Может использоваться как на окрашенных, так и на натуральных волосах. pH на уровне 6-7, для оптимального проникновения пигмента внутрь структуры волос. Идеален для блонда и пепельных оттенков. Подходит для любых оттенков блонда, осветленных брюнеток и седых волос.', 'Тонирующий шампунь "Система защиты для светлых волос" с запатентованной технологией Olaplex укрепляет, смягчает и нейтрализует нежелательные оттенки желтого, делая волосы мягкими, яркими и послушными. Может использоваться как на окрашенных, так и на натуральных волосах. pH на уровне 6-7, для оптимального проникновения пигмента внутрь структуры волос. Идеален для блонда и пепельных оттенков. Подходит для любых оттенков блонда, осветленных брюнеток и седых волос.<br><b>Применение:</b> Нанесите шампунь на влажные волосы, вспеньте и оставьте на 1-3 минуты. Тщательно смойте водой. Для более интенсивного результата оставьте на 5 минут. Частота использования продукта зависит от того, насколько холодный оттенок вам необходим. Общие рекомендации по использованию продукта 2-3 раза в неделю.', 1, 'active'),
('027', 'No.5', 'OLAPLEX Bond Maintenance Conditioner', 2300, 1750, 'data/images/ID027_min.png', '/bond_maintenance_conditioner_100', '1 x 100 ml <strong>Olaplex N°5 Bond Maintenance Conditioner | Укрепляющий кондиционер для увлажнения и блеска волос</strong>', 'Укрепляющий кондиционер Bond Maintenance восстанавливает поврежденные волосы, придает ему необходимое увлажнение и усиливает блеск без лишнего напряжения. Укрепляет, восстанавливает и регенерирует ломкие волосы предотвращает появление секущихся кончиков, облегчает расчесывание придает волосам увлажнение и блеск, не напрягает волос.', '', 1, 'active'),
('007', 'No.5', 'OLAPLEX Bond Maintenance Conditioner', 4150, 2990, 'data/images/ID007_min.png', '/bond_maintenance_conditioner', '1 x 250 ml <strong>Olaplex N°5 Bond Maintenance Conditioner | Укрепляющий кондиционер для увлажнения и блеска волос</strong>', 'Укрепляющий кондиционер Bond Maintenance восстанавливает поврежденные волосы, придает ему необходимое увлажнение и усиливает блеск без лишнего напряжения. Укрепляет, восстанавливает и регенерирует ломкие волосы предотвращает появление секущихся кончиков, облегчает расчесывание придает волосам увлажнение и блеск, не напрягает волос.', '', 1, 'active'),
('022', 'No.5', 'OLAPLEX Bond Maintenance Conditioner', 12740, 9990, 'data/images/ID022_min.png', '/bond_maintenance_conditioner_1000', '1 x 1000 ml <strong>Olaplex N°5 Bond Maintenance Conditioner | Укрепляющий кондиционер для увлажнения и блеска волос</strong>', 'Укрепляющий кондиционер Bond Maintenance восстанавливает поврежденные волосы, придает ему необходимое увлажнение и усиливает блеск без лишнего напряжения. Укрепляет, восстанавливает и регенерирует ломкие волосы предотвращает появление секущихся кончиков, облегчает расчесывание придает волосам увлажнение и блеск, не напрягает волос.', '', 1, 'active'),
('008', 'No.6', 'OLAPLEX Bond Smoother', 4190, 3390, 'data/images/ID008_min.png', '/bond_smoother', '1 x 100 ml <strong>Olaplex N°6 Bond Smoother| Восстанавливающий крем для укладки волос</strong>', 'Восстанавливающий крем для укладки волос Olaplex N°6 Bond Smoother прекрасно разглаживает вьющиеся волосы. Уход без смывания обеспечивает нужное увлажнение и защиту. Подходит для всех типов волос.', 'Восстанавливающий крем для укладки волос Olaplex N°6 Bond Smoother прекрасно разглаживает вьющиеся волосы. Уход без смывания обеспечивает нужное увлажнение и защиту. Подходит для всех типов волос.<br><b>Применение:</b>Нанесите небольшое количество Olaplex No.6 на влажные или сухие волосы по всей длине, уделяя наибольшее внимание кончикам. Хорошо распределите средство расческой. Высушите и уложите волосы.', 1, 'active'),
('009', 'No.7', 'OLAPLEX Bonding Oil', 4950, 3290, 'data/images/ID009_min.png', '/bonding_oil', '1 х 30 ml <strong>Olaplex No.7 Bonding Oil | Восстанавливающее масло для укладки волос</strong>', 'Высококонцентрированное легкое восстанавливающее масло для укладки волос. Ухаживающая формула целебного масла восстанавливает кератиновые связи внутри волосяного стержня, укрепляя по всей длине и улучшая текстуру. Придает заметный блеск, а мягкая фиксация сохранит укладку на весь день.', 'Высококонцентрированное легкое восстанавливающее масло для укладки волос. Ухаживающая формула целебного масла восстанавливает кератиновые связи внутри волосяного стержня, укрепляя по всей длине и улучшая текстуру. Придает заметный блеск, а мягкая фиксация сохранит укладку на весь день.<br><b>Применение:</b> Снимите защитный колпачок. Переверните флакон, мягко постучите указательным пальцем по основанию для дозирования капель средства. Нанесите небольшое количество средства на влажные или сухие волосы, уложите по желанию. Количество продукта определяется длиной и текстурой волос. <br><b>Совет профессионала:</b> добавьте несколько капель продукта в OLAPLEX No.6 для придания волосам непревзойденного блеска.', 1, 'active'),
('029', 'No.7', 'OLAPLEX Bonding Oil', 5880, 5590, 'data/images/ID029_min.png', '/bonding_oil_60', '1 х 60 ml <strong>Olaplex No.7 Bonding Oil | Восстанавливающее масло для укладки волос</strong>', 'Высококонцентрированное легкое восстанавливающее масло для укладки волос. Ухаживающая формула целебного масла восстанавливает кератиновые связи внутри волосяного стержня, укрепляя по всей длине и улучшая текстуру. Придает заметный блеск, а мягкая фиксация сохранит укладку на весь день.', 'Высококонцентрированное легкое восстанавливающее масло для укладки волос. Ухаживающая формула целебного масла восстанавливает кератиновые связи внутри волосяного стержня, укрепляя по всей длине и улучшая текстуру. Придает заметный блеск, а мягкая фиксация сохранит укладку на весь день.<br><b>Применение:</b> Снимите защитный колпачок. Переверните флакон, мягко постучите указательным пальцем по основанию для дозирования капель средства. Нанесите небольшое количество средства на влажные или сухие волосы, уложите по желанию. Количество продукта определяется длиной и текстурой волос. <br><b>Совет профессионала:</b> добавьте несколько капель продукта в OLAPLEX No.6 для придания волосам непревзойденного блеска.', 1, 'active'),
('015', 'No.8', 'OLAPLEX Bond Intense Moisture Mask', 4490, 2990, 'data/images/ID015_min.png', '/bond_intense_moisture_mask', '1 х 100 ml <strong>Olaplex No.8 Bond Intense Moisture Mask | Увлажняющая маска для восстановления структуры волос</strong>', 'Olaplex No.8 Bond Intense Moisture Mask - Маска-бонд интенсивно увлажняющая для восстановление структуры волос. Продукт восстанавливает волосы на молекулярном уровне. Он соединяет разрушенные дисульфидные связи в структуре волос, обеспечивая отсутствие повреждений в процессе любой салонной услуги для волос, а также ежедневных негативных воздействий (химических, термических и механических). Глубоко проникает в структуру волос, увлажняет и уплотняет их, придает волосам сияние, гладкость.', 'Olaplex No.8 Bond Intense Moisture Mask - Маска-бонд интенсивно увлажняющая для восстановление структуры волос. Продукт восстанавливает волосы на молекулярном уровне. Он соединяет разрушенные дисульфидные связи в структуре волос, обеспечивая отсутствие повреждений в процессе любой салонной услуги для волос, а также ежедневных негативных воздействий (химических, термических и механических). Глубоко проникает в структуру волос, увлажняет и уплотняет их, придает волосам сияние, гладкость.<br><b>Применение:</b> Нанести по длине на влажные волосы сразу после применения шампуня и равномерно распределить. Выдержать на волосах 10 минут. Смыть.', 1, 'active'),
('019', 'No.9', 'OLAPLEX Bond Protector Nourishing Hair Serum', 3780, 3390, 'data/images/ID019_min.png', '/bond_protector_nourishing_hair_serum', '1 x 90 ml <strong>Olaplex No. 9 Bond Protector Nourishing Hair Serum | Сыворотка для волос </strong>', 'Вдохновленные революционными технологиями в области ухода за волосами, Olaplex представляют свою первую в истории сыворотку для волос, которая защищает и балансирует ваши локоны. Питательная сыворотка для волос Olaplex №9 Bond Protector — это средство, которое не содержит силиконов, и предназначено для сухих и поврежденных волос. Она помогает усилить блеск волос и восполнить утраченную влагу.', 'Вдохновленные революционными технологиями в области ухода за волосами, Olaplex представляют свою первую в истории сыворотку для волос, которая защищает и балансирует ваши локоны. Питательная сыворотка для волос Olaplex №9 Bond Protector — это средство, которое не содержит силиконов, и предназначено для сухих и поврежденных волос. Она помогает усилить блеск волос и восполнить утраченную влагу.<br>Формула сыворотка основано на технологим Bond Building Technology™ и экстракте красных водорослей, которые создают невесомую питательную вуаль, обеспечивая при этом термозащиту до 232°C.<br>Насыщенная антиоксидантами сыворотка придает волосам глянцевый атласный блеск, делает их мягкими на ощупь, повышает гибкость и эластичность.', 1, 'active'),
('031', 'No.10', 'OLAPLEX Bond Shaper Curl Defining Gel', 4790, 3890, 'data/images/ID031_min.png', '/bond_shaper_curl_defining_gel', '1 x 200 ml <strong>Olaplex Nº.10 Bond Shaper™ Curl Defining Gel | Дефинирующий гель «Холодная волна»</strong>', 'Лёгкий гель для укладки, который формирует упругие, чётко очерченные локоны без склеивания и утяжеления. Укрепляет структуру волос благодаря технологии Bond Building, придаёт эластичность, блеск и стойкую форму завивки.', 'Лёгкий гель для укладки, который формирует упругие, чётко очерченные локоны без склеивания и утяжеления. Укрепляет структуру волос благодаря технологии Bond Building, придаёт эластичность, блеск и стойкую форму завивки.<br><b>Применение:</b> Нанесите небольшое количество геля на влажные волосы, равномерно распределите по длине, придавая форму локонам руками или с помощью диффузора. Не смывать. Подходит для ежедневного использования.', 1, 'active'),
('017', '', 'OLAPLEX 4-in-1 Moisture Mask', 8250, 7190, 'data/images/ID017_min.png', '/olaplex_4_in_1_moisture_mask', '1 x 370 ml <strong>Olaplex 4-in-1 Moisture Mask | Интенсивная бонд-маска 4 в 1 "Восстановление структуры волос"</strong>', 'Интенсивная бонд-маска восстанавливает волосы на молекулярном уровне. Средство содержит высококонцентрированный аминокислотный комплекс, который дает сразу 4 эффекта. Волосы получают больше блеска, увлажнения, гладкости и уплотняются почти в 2 раза. Эффект от применения можно увидеть после первого раза, время воздействия маски всего 10 минут. Маска восстанавливает дисульфидные связи в структуре волоса и защищает от ежедневных негативных воздействий. В составе средства содержатся масла конопли, авокадо, шиповника и гиалуроновая кислота. Эти компоненты являются естественными увлажнителями, дают волосам очень ценные жирные омега-кислоты и витамины.', 'Интенсивная бонд-маска восстанавливает волосы на молекулярном уровне. Средство содержит высококонцентрированный аминокислотный комплекс, который дает сразу 4 эффекта. Волосы получают больше блеска, увлажнения, гладкости и уплотняются почти в 2 раза. Эффект от применения можно увидеть после первого раза, время воздействия маски всего 10 минут. Маска восстанавливает дисульфидные связи в структуре волоса и защищает от ежедневных негативных воздействий. В составе средства содержатся масла конопли, авокадо, шиповника и гиалуроновая кислота. Эти компоненты являются естественными увлажнителями, дают волосам очень ценные жирные омега-кислоты и витамины.<br><b>Применение:</b> Тщательно вымойте волосы с использованием шампуня. Нанесите от 1 до 3 нажатий (в зависимости от характера и степени повреждения волос). Равномерно распределите и выдержите 10 минут. Тщательно смойте и выполните укладку', 1, 'active'),
('023', '', 'OLAPLEX Broad Spectrum Chelating Treatment', 7780, 5590, 'data/images/ID023_min.png', '/broad_spectrum_chelating_treatment', '1 x 370 ml <strong>Olaplex Broad Spectrum Chelating Treatment | Средство для глубокого очищения волос </strong>', 'Средство для глубокого очищения волос Olaplex Broad Spectrum Chelating – хелатирующий препарат широкого спектра действия, который образует хелаты, способные удалять не только грязь и жир, но и тяжелые металлы, минералы жесткой воды, хлор. Broad Spectrum Chelating способен проникать глубоко внутрь волосяного стержня, очищая, как мощный пылесос, кору волоса. Хелаты на уровне кортекса образуют химические реакции, эффективно удаляющие загрязнения, излишки жира, соли жесткой воды, хлор, остатки уходовых средств, тяжелые металлы и прочие загрязняющие вещества.', 'Средство для глубокого очищения волос Olaplex Broad Spectrum Chelating – хелатирующий препарат широкого спектра действия, который образует хелаты, способные удалять не только грязь и жир, но и тяжелые металлы, минералы жесткой воды, хлор. Broad Spectrum Chelating способен проникать глубоко внутрь волосяного стержня, очищая, как мощный пылесос, кору волоса. <br>Хелаты на уровне кортекса образуют химические реакции, эффективно удаляющие загрязнения, излишки жира, соли жесткой воды, хлор, остатки уходовых средств, тяжелые металлы и прочие загрязняющие вещества. В составе Olaplex Broad Spectrum Chelating содержится масляный экстракт австралийской сливы какаду, который насыщен витамином С, питающим волосы, способствующим синтезу коллагена и эластина. Это предотвращает выпадение волос, устраняет ломкость, стимулирует их рост, увлажняет.<br><b>Способ применения:</b>Предварительное очищение с Очищающий шампунь No.4C и тщательно промойте. Нанесите на волосы по частям обеими ладонями, равномерно насыщая. Добавьте больше по мере необходимости. Оставьте на 15-30 минут, в зависимости от текстуры волос и количества наращивания. При необходимости примените тепло, чтобы усилить эффект. Тщательно смойте, затем шампунем с No.4 Восстанавливающий шампунь Bond и состояние с Увлажняющая маска 4-в-1.', 1, 'active'),
('004', '', 'OLAPLEX Traveling Stylist Kit', 16290, 11990, 'data/images/ID004_min.png', '/traveling_stylist_kit', '1 x 100 ml <strong>Olaplex No.1 Hair Perfector | Эликсир «Совершенство Волос»</strong>', 'Olaplex Bond Multiplier и Bond Perfector – уверенность, что волосы посетителя будут максимально защищены от любых повреждений во время оказания какой либо услуги.', '', 1, 'active'),
('005', '', 'OLAPLEX Salon Intro Kit', 38740, 32550, 'data/images/ID005_min.png', '/salon_intro_kit', '1 x 525 ml <strong>Olaplex No.1 Hair Perfector | Эликсир «Совершенство Волос»</strong>', 'Olaplex Bond Multiplier и Bond Perfector – это гарантированная защита волос посетителя от возможных повреждений во время салонных процедур.', '', 1, 'active'),
('030', '', 'OLAPLEX Набор для укрепления и блеска волос', 6790, 6450, 'data/images/ID030_min.png', '/in_good_repair_hair_kit', '1 x 30 ml <strong>No.3 Hair Perfector</strong> | <br>1 x 100 ml <strong>No.4 Bond Maintenance Shampoo</strong> | <br>1 x 100 ml <strong>No.5 Bond Maintenance Conditioner</strong> | <br>1 x 30 ml <strong>No.7 Bonding Oil</strong>', 'Набор для восстановления волос In Good Repair Hair Kit — это четыре культовых средства Olaplex в одном комплекте, созданные для разглаживания, укрепления и восстановления волос по всей длине. Подходит для всех типов волос и работает на основе уникальной Bond Building Technology, которая снижает ломкость и возвращает локам здоровый вид.', 'Набор для восстановления волос In Good Repair Hair Kit — это четыре культовых средства Olaplex в одном комплекте, созданные для разглаживания, укрепления и восстановления волос по всей длине. Подходит для всех типов волос и работает на основе уникальной Bond Building Technology, которая снижает ломкость и возвращает локам здоровый вид.<br><b>В набор входят:</b><br>- No.3 Hair Perfector — легендарное средство для восстановления, которое возвращает повреждённым волосам мягкость, блеск и шелковистость. Используется перед шампунем для максимального эффекта.<br>- No.4 Bond Maintenance Shampoo — увлажняющий шампунь мягко очищает волосы от загрязнений и излишков себума, питает и защищает от секущихся кончиков.<br>- No.5 Bond Maintenance Conditioner — лёгкий кондиционер облегчает расчесывание, устраняет признаки повреждений и дарит волосам здоровое сияние.<br>- No.7 Bonding Oil — многофункциональное масло для блеска и защиты. Делает волосы гладкими, ухоженными и защищает от термического воздействия до 232°C.', 0, 'active'),
('026', '', 'OLAPLEX Unbreakable Blondes Mini Kit', 3840, 2850, 'data/images/ID026_min.png', '/unbreakable_blondes_mini_kit', '1 x 110 ml <strong>Olaplex Unbreakable Blondes Mini Kit | Набор миниатюр для светлых и седых волос </strong>', 'Вдохновленные революционными технологиями в области ухода за волосами, Olaplex представляют свою первую в истории сыворотку для волос, которая защищает и балансирует ваши локоны. Питательная сыворотка для волос Olaplex №9 Bond Protector — это средство, которое не содержит силиконов, и предназначено для сухих и поврежденных волос. Она помогает усилить блеск волос и восполнить утраченную влагу.', 'Unbreakable Blondes — набор миниатюр для светлых и седых волос. Ознакомительный набор для ухода за натуральными светлыми, осветленными и седыми волосами. Двухкомпонентная система миниатюр Nº0 и Nº3 создана для восстановления поврежденных и ломких волос. No.4P бережно удаляет загрязнение, тонизирует и осветляет, а No.8 реставрирует и возвращает волосам их естественную мягкость, гладкость и блеск.', 0, 'active');
